# Strategy checklist
def evaluate_strategy(doc):
    checks = [
        ("Clear problem diagnosis", len(doc.get("context",{}).get("problems",[])) > 0),
        ("Testable principles", any("will" in p.lower() for p in doc.get("principles",[]))),
        ("Measurable vision", "NPS" in doc.get("vision","") or "percent" in doc.get("vision","")),
        ("Tradeoffs explicit", len(doc.get("strategic_bets",{}).get("wont_do",[])) > 0),
        ("Risks identified", len(doc.get("risks",[])) > 0),
    ]
    return sum(1 for _, ok in checks if ok), len(checks)

