@dataclass
class DACIDecision:
    title: str
    driver: str      # 1 person who drives the process
    approver: str    # 1 person who makes the final call
    contributors: list  # 2-5 people who provide input
    informed: list   # everyone else who needs to know

    def validate(self):
        errors = []
        if not self.driver: errors.append("Driver is required")
        if not self.approver: errors.append("Approver is required")
        if len(self.contributors) < 1: errors.append("At least 1 contributor")
        if self.driver == self.approver:
            errors.append("Driver and Approver should be different")
        return errors

