# Stakeholder mapping template
class StakeholderMap:
    def __init__(self):
        self.stakeholders = {}  # name -> {role, influence, interest, engagement}

    def add(self, name, role, influence=5, interest=5):
        self.stakeholders[name] = {
            "role": role,
            "influence": influence,  # 1-10
            "interest": interest,    # 1-10
            "engagement": "",
            "concerns": []
        }

    def prioritize(self):
        # High influence + high interest = manage closely
        # High influence + low interest = keep satisfied
        # Low influence + high interest = keep informed
        # Low influence + low interest = monitor
        categories = {"manage": [], "satisfy": [], "inform": [], "monitor": []}
        for name, s in self.stakeholders.items():
            if s["influence"] >= 7 and s["interest"] >= 7:
                categories["manage"].append(name)
            elif s["influence"] >= 7:
                categories["satisfy"].append(name)
            elif s["interest"] >= 7:
                categories["inform"].append(name)
            else:
                categories["monitor"].append(name)
        return categories

    def communication_plan(self):
        plans = []
        for name, s in self.stakeholders.items():
            if s["influence"] >= 7:
                plans.append({"name": name, "freq": "weekly 1:1", "format": "briefing"})
            elif s["interest"] >= 7:
                plans.append({"name": name, "freq": "biweekly", "format": "email update"})
        return plans

# Meeting facilitation: decision-forcing
class MeetingFacilitator:
    @staticmethod
    def decision_forcing(context, options, criteria):
        """Force a decision by scoring options against criteria."""
        scores = []
        for opt_name, opt in options.items():
            score = sum(criteria[c] * opt.get(c, 0) for c in criteria)
            scores.append((score, opt_name))
        scores.sort(reverse=True)
        return scores

# Technical debt tracker
from dataclasses import dataclass
from enum import Enum

class Severity(Enum): LOW=0; MEDIUM=1; HIGH=2; CRITICAL=3

@dataclass
class DebtItem:
    title: str
    description: str
    severity: Severity
    cost_weeks: float  # estimated person-weeks to fix
    location: str  # file, service, area
    tags: list = None

class DebtRegister:
    def __init__(self):
        self.items = []

    def add(self, item):
        self.items.append(item)

    def prioritize(self):
        scored = []
        for item in self.items:
            urgency = item.severity.value * 10 - item.cost_weeks
            scored.append((urgency, item))
        scored.sort(reverse=True)
        return [item for _, item in scored]

    def write_down(self, name, cost_weeks, reason):
        """Intentional debt: document why you’re taking it on."""
        self.items.append(DebtItem(
            title=name,
            description=f"Intentional: {reason}",
            severity=Severity.MEDIUM,
            cost_weeks=cost_weeks,
            location="",
            tags=["intentional"]
        ))

    def total_cost(self):
        return sum(i.cost_weeks for i in self.items)

    def report(self):
        return {
            "total_items": len(self.items),
            "total_cost_weeks": self.total_cost(),
            "by_severity": {sev: len([i for i in self.items if i.severity == sev])
                            for sev in Severity},
            "critical_items": [i for i in self.items if i.severity == Severity.CRITICAL]
        }

