            "adopters_expected": adopters_expected,
            "adopters_actual": 0,
            "started": __import__("time").time()
        })

    def record_adoption(self, name, team):
        for i in self.initiatives:
            if i["name"] == name:
                i["adopters_actual"] += 1

    def influence_score(self):
        scores = []
        for i in self.initiatives:
            if i["adopters_expected"] > 0:
                ratio = i["adopters_actual"] / i["adopters_expected"]
                scores.append({"name": i["name"], "adoption_ratio": ratio,
                               "strategy": i["strategy"]})
        return scores

# Making the right thing easy: migration tool pattern
class AutomatedMigration:
    def __init__(self, from_pattern, to_pattern):
        self.from_pattern = from_pattern
        self.to_pattern = to_pattern
        self.codemod_rules = []  # ast-based transformation rules

    def add_rule(self, description, match_fn, replace_fn):
        self.codemod_rules.append({"desc": description,
                                   "match": match_fn, "replace": replace_fn})

    def dry_run(self, code):
        changes = []
        for rule in self.codemod_rules:
            matches = rule["match"](code)
            for m in matches:
                changes.append({"rule": rule["desc"], "location": m})
        return changes

    def apply(self, code):
        for rule in self.codemod_rules:
            code = rule["replace"](code)
        return code

# Estimation tools
import math

class ThreePointEstimate:
    def __init__(self, optimistic, most_likely, pessimistic):
        self.O = optimistic
        self.M = most_likely
        self.P = pessimistic

    @property
    def expected(self):
        return (self.O + 4*self.M + self.P) / 6

    @property
    def std_dev(self):
        return (self.P - self.O) / 6

    def confidence(self, target_weeks):
        """Probability of completing within target weeks (normal approx)."""
        z = (target_weeks - self.expected) / max(self.std_dev, 0.01)
        return 0.5 * (1 + math.erf(z / math.sqrt(2)))

    def weeks_for_confidence(self, pct):
        z = {0.5: 0, 0.7: 0.52, 0.8: 0.84, 0.9: 1.28, 0.95: 1.65}[pct]
        return self.expected + z * self.std_dev

    def __repr__(self):
        return f"{self.expected:.1f} +/- {self.std_dev:.1f} weeks"

# Example: estimate a migration
migration = ThreePointEstimate(optimistic=4, most_likely=8, pessimistic=16)
