print(f"90% confidence: {migration.weeks_for_confidence(0.9):.0f} weeks")
print(f"Probability within 10 weeks: {migration.confidence(10)*100:.0f}%")

# OKR template
class OKR:
    def __init__(self, objective, krs):
        self.objective = objective
        self.key_results = [{"kr": kr, "target": 100, "actual": 0} for kr in krs]
        self.weight = 1.0  # 0.0 to 1.0

    def update(self, kr_idx, actual):
        if 0 <= kr_idx < len(self.key_results):
            self.key_results[kr_idx]["actual"] = actual

    def progress(self):
        if not self.key_results: return 0
        return sum(min(kr["actual"] / max(kr["target"], 1), 1)
                   for kr in self.key_results) / len(self.key_results)

    def is_on_track(self):
        mid = __import__("time").time() % (365*86400) / (365*86400)
        return self.progress() >= mid * 0.8

# Reference class forecasting
class ReferenceClass:
    def __init__(self):
        self.projects = []  # [(estimated_weeks, actual_weeks, complexity), ...]

    def add_project(self, estimated, actual, complexity="medium"):
        self.projects.append((estimated, actual, complexity))

    def multiplier(self):
        if not self.projects: return 2.5
        ratios = [a/e for e, a, _ in self.projects if e > 0]
        return sum(ratios) / len(ratios)

    def predict(self, naive_estimate):
        return naive_estimate * self.multiplier()

# Culture health survey
class CultureSurvey:
    DIMENSIONS = ["psychological_safety", "blamelessness", "continuous_improvement",
                  "engineering_excellence", "open_disagreement"]

    def __init__(self):
        self.responses = []  # list of dicts: {dimension: score (1-5), comment: str}

    def add_response(self, dimension, score, comment=""):
        self.responses.append({"dimension": dimension, "score": score, "comment": comment})

    def dimension_avg(self, dimension):
        scores = [r["score"] for r in self.responses if r["dimension"] == dimension]
        return sum(scores) / len(scores) if scores else 0

    def report(self):
        return {d: self.dimension_avg(d) for d in self.DIMENSIONS}

    def weakest(self):
        return min(self.DIMENSIONS, key=lambda d: self.dimension_avg(d))

