# Writing quality checker
class WritingReview:
    WEAK_WORDS = ["might", "maybe", "possibly", "consider", "think about",
                  "should", "could", "would", "seems", "appears"]

    @staticmethod
    def check(text):
        issues = []
        words = text.lower().split()

        for w in WritingReview.WEAK_WORDS:
            if w in words:
                issues.append(f"Weak word: '{w}' - replace with stronger language")

        # Check for passive voice indicators
        for match in ["was ", "were ", "been ", "being "]:
            if match in text.lower() and " by " in text.lower():
                issues.append(f"Passive voice detected near '{match}'")

        paragraphs = [p for p in text.split("\n") if p.strip()]
        for p in paragraphs:
            if len(p) > 500:
                issues.append(f"Paragraph too long ({len(p)} chars): split into multiple paragraphs")

        return {"score": max(0, 10 - len(issues)), "issues": issues}

# TL;DR generator
def make_tldr(doc_text):
    """Extract first sentence of each section for a summary."""
    lines = doc_text.strip().split("\n")
    key_points = []
    for line in lines:
        if line.startswith("## ") or line.startswith("### "):
            section = line.strip("# ").strip()
        elif line.strip() and not line.startswith("#"):
            first_sentence = line.strip().split(".")[0]
            if first_sentence and len(first_sentence) > 20:
                key_points.append(f"  - {first_sentence}.")
    return "TL;DR:\n" + "\n".join(key_points[:5])

