# Brag doc / promotion packet template
class BragDoc:
    def __init__(self, name, current_level, target_level):
        self.name = name
        self.current_level = current_level
        self.target_level = target_level
        self.achievements = []  # {impact, team, metrics, date}
        self.endorsements = []  # {name, role, quote}

    def add_achievement(self, impact, team, metrics):
        self.achievements.append({
            "impact": impact,
            "team": team,
            "metrics": metrics,
            "date": __import__("time").time()
        })

    def add_endorsement(self, name, role, quote):
        self.endorsements.append({"name": name, "role": role, "quote": quote})

    def generate_packet(self):
        return {
            "candidate": {"name": self.name, "from": self.current_level,
                          "to": self.target_level},
            "impact_summary": f"{len(self.achievements)} achievements across "
                              f"{len(set(a['team'] for a in self.achievements))} teams",
            "key_metrics": [a["metrics"] for a in self.achievements[:5]],
            "endorsements": self.endorsements[:3]
        }

    def promotion_readiness(self):
        cross_team = len(set(a["team"] for a in self.achievements))
        has_mentorship = any("mentor" in a["impact"].lower() or "sponsor" in a["impact"].lower()
                            for a in self.achievements)
        return {
            "cross_team_impact": f"{cross_team} teams",
            "mentorship_evidence": has_mentorship,
            "endorsement_count": len(self.endorsements),
            "ready": cross_team >= 3 and has_mentorship and len(self.endorsements) >= 2
        }

# Promotion committee simulation
def promotion_committee(projected_impact, endorsements, brag_doc):
    score = 0
    score += 30 if projected_impact.get("cross_team") else 0
    score += 20 if projected_impact.get("org_wide") else 10
    score += 25 if len(endorsements) >= 3 else 0
    score += 25 if brag_doc.promotion_readiness()["ready"] else 0
    result = "Promote" if score >= 70 else "Not Yet"
    return {"score": score, "result": result, "feedback": []}
